import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import bookingService from "../services/bookingService";
import { useAuth } from "../context/AuthContext";
import { useToast } from "../components/Toast";

export default function Bookings() {
  const { user } = useAuth();
  const showToast = useToast();
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  const load = () => {
    if (!user) {
      setLoading(false);
      return;
    }

    bookingService
      .getByUser(user.id)
      .then(setBookings)
      .catch(() => showToast("Could not load bookings", "error"))
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    load();
  }, [user]);

  const cancelBooking = async (id) => {
    if (!window.confirm("Cancel full booking?")) return;

    try {
      await bookingService.cancel(id);
      showToast("Booking cancelled", "success");
      load();
    } catch {
      showToast("Cancel failed", "error");
    }
  };

  const partialCancel = async (bookingId) => {
    const input = prompt("Enter seat IDs to cancel (comma separated)");

    if (!input) return;

    try {
      const seatIds = input.split(",").map((s) => Number(s.trim()));

      await bookingService.partialCancel(bookingId, seatIds);

      showToast("Seats cancelled", "success");
      load();
    } catch {
      showToast("Partial cancel failed", "error");
    }
  };

  if (!user) {
    return (
      <div className="container">
        <div className="empty-state">
          <p>
            Please <Link to="/login">login</Link>
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="container">
      <h2>My Bookings</h2>

      {loading ? (
        <p>Loading...</p>
      ) : bookings.length === 0 ? (
        <p>No bookings</p>
      ) : (
        bookings.map((b) => (
          <div key={b.bookingId} className="card" style={{ margin: "1rem 0" }}>
            <div className="card-body">
              <h3>🎬 {b.movieTitle}</h3>

              <p>
                🏛️ {b.theaterName} — {b.screenName}
              </p>

              <p>💺 Seats: {b.seatNumbers?.join(", ")}</p>

              <p>💰 ₹{b.totalPrice}</p>

              <p>Status: {b.bookingStatus}</p>

              {b.bookingStatus === "CONFIRMED" && (
                <>
                  <button onClick={() => cancelBooking(b.bookingId)}>
                    Cancel Full
                  </button>

                  <button
                    style={{ marginLeft: "10px" }}
                    onClick={() => partialCancel(b.bookingId)}
                  >
                    Cancel Seats
                  </button>
                </>
              )}
            </div>
          </div>
        ))
      )}
    </div>
  );
}
